// Code generated by selo gen --lang rust. DO NOT EDIT.

use crate::data::CEP_RANGES;
use crate::mod11::{self, SeloError};

/// Return the UF whose prefix range contains prefix, or None.
fn range_for(prefix: i32) -> Option<&'static str> {
    CEP_RANGES
        .iter()
        .find(|r| r.from <= prefix && prefix <= r.to)
        .map(|r| r.uf)
}

/// Report whether value is a CEP whose prefix maps to a UF.
pub fn validate_cep(value: &str) -> bool {
    let d = mod11::only_digits(value);
    if d.len() != 8 {
        return false;
    }
    let prefix: i32 = d[0..3].parse().unwrap_or(-1);
    range_for(prefix).is_some()
}

/// Mask a CEP as #####-###, or return an error on bad length.
pub fn format_cep(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 8 {
        return Err(SeloError::InvalidLength);
    }
    Ok(format!("{}-{}", &d[0..5], &d[5..8]))
}

/// Return the UF whose prefix range contains value, or an error.
pub fn origin_cep(value: &str) -> Result<String, SeloError> {
    let d = mod11::only_digits(value);
    if d.len() != 8 {
        return Err(SeloError::InvalidLength);
    }
    let prefix: i32 = d[0..3].parse().unwrap_or(-1);
    match range_for(prefix) {
        Some(uf) => Ok(uf.to_string()),
        None => Err(SeloError::InvalidFormat),
    }
}

/// Return a random, valid 8-digit CEP (unformatted).
pub fn generate_cep() -> String {
    let r = &CEP_RANGES[mod11::rand_int(CEP_RANGES.len() as u64 - 1) as usize];
    let prefix = r.from + mod11::rand_int((r.to - r.from) as u64) as i32;
    let suffix = mod11::rand_int(99999);
    format!("{:03}{:05}", prefix, suffix)
}

#[cfg(test)]
mod tests {
    use super::*;

    fn vector() -> serde_json::Value {
        let p = concat!(env!("CARGO_MANIFEST_DIR"), "/vectors/cep.json");
        let s = std::fs::read_to_string(p).expect("read vector");
        serde_json::from_str(&s).expect("parse vector")
    }

    #[test]
    fn validate_cases() {
        for case in vector()["validate"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let valid = case["valid"].as_bool().unwrap();
            assert_eq!(valid, validate_cep(input), "validate {}", input);
        }
    }

    #[test]
    fn format_cases() {
        for case in vector()["format"].as_array().unwrap() {
            let input = case["input"].as_str().unwrap();
            let is_error = case
                .get("error")
                .and_then(|e| e.as_str())
                .map(|e| !e.is_empty())
                .unwrap_or(false);
            if is_error {
                assert!(format_cep(input).is_err(), "format expected err {}", input);
            } else {
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, format_cep(input).unwrap(), "format {}", input);
            }
        }
    }

    #[test]
    fn origin_cases() {
        if let Some(arr) = vector().get("origin").and_then(|o| o.as_array()) {
            for case in arr {
                let input = case["input"].as_str().unwrap();
                let want = case["output"].as_str().unwrap();
                assert_eq!(want, origin_cep(input).unwrap(), "origin {}", input);
            }
        }
    }

    #[test]
    fn generate_round_trip() {
        for _ in 0..100 {
            let v = generate_cep();
            assert!(validate_cep(&v), "generate produced invalid: {}", v);
        }
    }
}
